import java.util.*;
import java.util.stream.*;

public class ProductRepository {

    public record Product(int id, String name, String category, double price) {}

    interface Repository<T, ID> {
        void save(T entity);
        Optional<T> findById(ID id);
        List<T> findAll();
        void delete(ID id);
        int count();
    }

    static class InMemoryProductRepository implements Repository<Product, Integer> {
        private final Map<Integer, Product> store = new LinkedHashMap<>();

        public void save(Product product) {
            store.put(product.id(), product);
        }

        public Optional<Product> findById(Integer id) {
            return Optional.ofNullable(store.get(id));
        }

        public List<Product> findAll() {
            return new ArrayList<>(store.values());
        }

        public void delete(Integer id) {
            store.remove(id);
        }

        public int count() { return store.size(); }

        public List<Product> findByCategory(String category) {
            // Return products where category matches (case-insensitive)
            return new ArrayList<>(); // TODO
        }

        public List<Product> findByMaxPrice(double maxPrice) {
            // Return products with price <= maxPrice, sorted by price ascending
            return new ArrayList<>(); // TODO
        }
    }

    public static void main(String[] args) {
        InMemoryProductRepository repo = new InMemoryProductRepository();
        repo.save(new Product(1, "Laptop", "Electronics", 999.99));
        repo.save(new Product(2, "Mouse", "Electronics", 29.99));
        repo.save(new Product(3, "Desk", "Furniture", 249.99));

        System.out.println("Count: " + repo.count());
        System.out.println("Find 2: " + repo.findById(2).map(Product::name).orElse("Not found"));
        System.out.println("Electronics: " + repo.findByCategory("electronics").size());
        repo.delete(1);
        System.out.println("After delete: " + repo.count());
        System.out.println("Cheap items: " + repo.findByMaxPrice(250.0).stream().map(Product::name).collect(java.util.stream.Collectors.toList()));
    }
}

