public class ReportGenerator {

    // Template method — defines the algorithm skeleton
    public final String generate(List<String[]> rawData) {
        List<String[]> processed = processData(rawData);
        String formatted = formatOutput(processed);
        return export(formatted);
    }

    // Hook: default is identity (no filtering)
    protected List<String[]> processData(List<String[]> data) {
        return data;
    }

    // Abstract steps to be implemented by subclasses
    protected String formatOutput(List<String[]> data) { return ""; }
    protected String export(String content) { return content; }

    static class CsvReportGenerator extends ReportGenerator {
        @Override
        protected String formatOutput(List<String[]> data) {
            // Join each row with commas, join rows with newlines
            StringBuilder sb = new StringBuilder();
            for (String[] row : data) {
                sb.append(String.join(",", row)).append("\n");
            }
            return sb.toString().trim();
        }

        @Override
        protected String export(String content) {
            return "CSV:\n" + content;
        }
    }

    static class JsonReportGenerator extends ReportGenerator {
